class ChatRequest(BaseModel):
    messages: List[Message]          # <-- often the source of the problem
    choices: List[Choices]

from pydantic import root_validator

class ChatMessage(Message):
    @root_validator(pre=True)
    def ensure_required_fields(cls, values):
        # Fill missing optional fields with defaults
        values.setdefault('timestamp', int(time.time()))
        return values

def safe_serialize(obj: BaseModel) -> Any:
    try:
        return obj.__pydantic_serializer__.to_python(obj)
    except PydanticSerializationError as e:
        logger.exception("Failed to serialize %s: %s", obj.__class__, e)
        raise CustomSerializationError from e
